var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으엥~","JPN":"ひいい～ん。","ENG":"Hnngg...","TWN":"呃嗯～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"간신히 절반지점까지 헤엄쳤는데 억지로 끌려 나왔어.","JPN":"やっと半分まで泳いだのに、むりやり引き上げられたぁ。","ENG":"I was finally halfway to the end. Why did you pull me out?","TWN":"好不容易游了一半，結果卻被強行拉上岸了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"미, 미안합니다. 전 혹시나 물에 빠진 줄 알고......","JPN":"ご、ごめんなさい。てっきり溺れたのかと思って……","ENG":"I-I'm sorry. I thought you were drowning...","TWN":"對、對不起，我以為妳溺水了……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아니에요. 그런 자세로 헤엄을 치고 있으면 당연히 오해를 살 수 밖에 없죠.","JPN":"いいえ。変な姿勢で泳いでたので、誤解されて当然です。","ENG":"Don't be. Of course you thought she was drowning.","TWN":"沒關係。用那種姿勢游泳，不被誤會才怪。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"어차피 저런 식이면 레인 끝에 도착하기도 전에 탈진했을 테니 잘 해주셨어요.","JPN":"どうせあんな姿勢じゃ、プールの端に到着する前に気力が尽きていたと思うので、よくやってくれました。","ENG":"Swimming like that, she would have exhausted herself before reaching the other end. Thank you for helping her.","TWN":"反正用那種方式繼續游的話，還沒到終點就會虛脫的，所以妳做得很好。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스, 그렇게 팔다리를 막무가내로 휘젓는 수영은 비효율적입니다.","JPN":"イーディス、そんなに手足を無駄に振り回す泳ぎ方は非効率的です。","ENG":"Edith, flailing your limbs like that isn't an effective way of swimming.","TWN":"伊蒂絲，在水裡亂抓亂扒是沒有效率的游泳方式。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"다시 가르쳐줄 테니 이번엔 제대로......","JPN":"もう一度教えますから、今回はちゃんと……","ENG":"Let me teach you again. This time, we will—","TWN":"我再教妳一次，這次要認真學……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으으, 열심히 헤엄쳤더니 너무 졸려~ 더는 못해~","JPN":"うう、頑張って泳いだから眠すぎる～もうダメ～。","ENG":"Ugh, I swam too hard. I'm toooo tired. I can't do it anymooore.","TWN":"呃，我游到沒力氣了，好睏喔～我游不下去了～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"......쿠울......","JPN":"……すやすや……","ENG":"Zzz...","TWN":"……呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어머? 선 채로 잠들었네요? 저런 게 정말로 가능하구나.","JPN":"あれ？　立ったまま眠ってしまいましたね？　あんなのって本当にできるんだ。","ENG":"Oh, she fell asleep standing up. I didn't know that was possible.","TWN":"哎呀？竟然站著睡著了呢？真是太神奇了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......제 연구조교 시절을 떠올리게 하는 모습이로군요.","JPN":"……私が研究所で助手だった頃を思い出しますね。","ENG":"She reminds me of myself when I was an assistant researcher.","TWN":"……這簡直就像我助教時代的樣子呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"잠깐 앉혀두면 곧 깨어날 겁니다. 걱정 마시길.","JPN":"しばらく座らせておいたらすぐ起きますよ。心配しないでください。","ENG":"Let her sit on her chair for a while, and she'll wake up soon. Don't worry.","TWN":"讓她坐一會兒很快會醒來的，不用擔心。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"제 이름은 옌 싱 란체스터라고 해요. 두 분은 호텔의 투숙객들이군요?","JPN":"私の名前はイェン・シング・ランチェスターと申します。お二人はホテルの宿泊客ですよね？","ENG":"My name is Yen Xing Lanchester. Are you two staying at the hotel?","TWN":"我叫嫣杏·蘭賈斯特，兩位是飯店的入住客人吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어머, 어떻게 아셨어요?","JPN":"おや、どうやって知ったんですか？","ENG":"Oh, how did you know?","TWN":"咦，妳是怎麼知道的？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"후훗, 학교의 안위를 책임지려면 학교 주변의 소식에도 밝아야 하니까요.","JPN":"ふふっ、学校の安全を担う人間として、学校周辺の状況もいろいろと知っておく必要がありますから。","ENG":"Hah hah. As someone in charge of the peace of my school, I must be aware of what's going on around it at all times.","TWN":"呵呵，為了維護學校安全，必須掌握周邊的訊息才行。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"침식체가 나타났다고 들었는데, 다행히 잘 해결된 모양이네요.","JPN":"侵食体が現れたと聞いたんですが、無事に解決できたようですね。","ENG":"I heard some C.O.s showed up. Someone must have taken good care of them.","TWN":"我聽說有侵蝕體出沒，但所幸事情似乎都順利解決了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"두 분은 어쩐 일로 여기 오게 되셨나요?","JPN":"お二人はどのようなご用件でここに来たんですか？","ENG":"May I ask what brings you two to this school?","TWN":"那你們兩位來這裡是有什麼事嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아, 저희는 운명적인 모험을 하고 있어요.","JPN":"あ、私たちは運命的な冒険をしてるんです。","ENG":"Oh, we're on a fateful adventure.","TWN":"啊，我們正在進行命運之冒險。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"이쪽에 계신 의뢰인 분과 불타는 사랑을 해줄 애인을 찾기 위해 이곳 저곳을 떠도는 중이랍니다.","JPN":"こちらの依頼人の方と、燃えるような恋をしてくれる恋人を探すために、あちこちを回ってます。","ENG":"To find someone who can ignite burning love in this lady here. So far, we haven't had any luck.","TWN":"我們正在四處尋找能給這位委託人帶來一場熱戀的戀人。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아악! 이봐요! 그렇게 말하니까 내가 엄청나게 굶주린 거 같잖아요!","JPN":"あっ！　ちょっと！　そんな風に言うと、私がものすごく恋愛に飢えてるように見えるじゃないですか！","ENG":"Argh! Hey, do you really have to make me look as if I'm desperate for love?","TWN":"啊！喂喂！妳這樣說好像我很飢渴一樣！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라, 아니었나요?","JPN":"おや、違うんですか？","ENG":"Erm, aren't you?","TWN":"嗯？難道我說錯了嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"따, 딱히 꼭 틀린 건 아니지만 어감이 중요하다고요, 어감이!","JPN":"べ、別に否定はしませが、ニュアンスが大事なんですよ、ニュアンス！","ENG":"I-I am, sort of, but I don't like the nuance.","TWN":"雖、雖然不完全是錯的，但重要的是語氣啦，語氣！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"내가 찾고 싶은 운명의 상대는 흔한 애인이 아니라 오롯이 나를 위해 헌신해줄 수 있는 사람!","JPN":"私が見つけたい運命の相手は、ありふれた恋人じゃなくて、私だけのためにすべてを捧げてくれる人！","ENG":"I'm not just looking for a lover, but someone who can devote himself to me!","TWN":"我的命運之人不是普通的戀人，而是一個能夠完全為我獻身的人！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아가페의 현신 그 자체라고!","JPN":"アガペーの現身そのものなんです！","ENG":"I don't want a fling—I want unconditional love!","TWN":"也就是愛本身的化身！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"운명의 상대라...... 낭만적인 얘기군요.","JPN":"運命の相手ですか……ロマンチックな話ですね。","ENG":"So, a soul mate, huh? How romantic!","TWN":"命運之人……真是浪漫呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"방학 중이라 학생들 밖에 없는 학교를 그런 목적으로 찾아오셨다는 게 좀 걸리긴 합니다만......","JPN":"生徒しかいない夏休み中の学校を、そんな目的で訪ねて来たことが少々気にかかりますが……","ENG":"Although I can't help but wonder why you'd look for him in a school full of kids, especially during its summer break where none of the adult faculty members are here to watch them.","TWN":"不過現在學校放假，學校裡就只有學生，你們為了這個目的來有點……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저, 전 등 떠밀려서 왔을 뿐이에요. 딱히 그런 불순한 목적은 없다고요!","JPN":"わ、私はむりやり連れてこられただけなんです。特にそのような不純な目的はありません！","ENG":"Th-this wasn't even my idea. I don't like kids, anyway!","TWN":"我、我是被她們硬拉過來的，沒有什麼不純的目的！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어라? 헬기? 이쪽으로 오는 거 맞죠?","JPN":"あれ？　ヘリ？　こっちに向かってるのでしょうか？","ENG":"Err? That's a chopper. It's coming this way, right?","TWN":"咦？直升機？而且好像往這裡來了耶？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"방송국 헬기 아닐까요? 손이라도 흔들고 있으면 TV에 나올지도 몰라요.","JPN":"テレビ局のヘリじゃないでしょうか？　手を振ってみたらテレビに出れるかもしれませんよ。","ENG":"Maybe it's from a television station. Let's wave hands. We might be on TV.","TWN":"是不是電視臺的直升機啊？要是對他們揮手的話，說不定會上電視呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"야호~ 여기요, 여기!","JPN":"やほ～こっちです、こっち！","ENG":"Yoo-hoo! Here, over here!","TWN":"哟呵～這裡，看這裡！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"......뭔가 이상하군요. 여긴 항공관제 구역이라 외부 항공기가 함부로 접근할 수 없을 텐데.","JPN":"……何かおかしいですね。ここは航空管制エリアなので、外部の航空機は勝手に入れないはずですが。","ENG":"This doesn't make sense. Air traffic is restricted in this area. External aircraft are not allowed to fly here.","TWN":"……有點奇怪呢。這裡是航空管制地區，外部飛機是不能擅自靠近這裡的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"게다가 저 반짝이는 거, 카메라가 아닌 거 같은데요?","JPN":"しかもあの光ってるの、カメラじゃないと思いますよ。","ENG":"Besides, that blinking light doesn't look like it's from a camera.","TWN":"而且那個發光的東西，好像不是攝影機吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"앗, 저거. 이제 보니 군사용 헬기네요. 무장한 용병들이 타고 있는 거 같은데?","JPN":"あっ、あれって。よく見たら軍事用ヘリですね。武装した傭兵たちが乗っているみたいです。","ENG":"Ah, that. On a second look, I can tell that's a military chopper. With armed mercenaries in it.","TWN":"啊，那個是！現在仔細一看，才發現那是軍用直升機，還有武裝傭兵坐在上面耶？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그, 그냥 지나가는 길인 거겠죠? 하하......","JPN":"た、ただ通りすぎるだけですよね？　はは……","ENG":"Th-they have to be just passing by, right? Hah hah...","TWN":"應、應該只是路過的吧？哈哈……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그렇다고 하기엔 레펠이 이쪽으로 떨어지는데요?","JPN":"それにしては、こっちに向かって降下してきてるようですよ？","ENG":"But they're rappelling down this way.","TWN":"但是他們已經降下垂降繩索了？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아하! 아마 저기엔 건장한 성인남성들이 잔뜩 타고 있을 테니까, 운명의 상대를 기대해 볼만하지 않을까요?","JPN":"そうだ！　恐らくあっちにはがっちり系の成人男性がいっぱい乗ってるはずですから、\\n運命の相手を期待してみてもいいんじゃないですか？","ENG":"A-ha! Almost all of them look like brawny adult men. Maybe one of them is your soul mate.","TWN":"啊哈！那裡面一定有很多健壯的成年男子，說不定有妳的命運之人喔？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"음, 과연. 저 분이 학생들을 노리고 온 게 아니라면 저도 안심이네요.","JPN":"うむ、なるほど。あの方が生徒狙いで来たわけじゃないなら、私も安心です。","ENG":"Mm, yes. I'm glad she's not here to rob the cradle.","TWN":"嗯，果然。她的目標不是學生，那我可以放心了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그러니까, 애들한텐 나도 관심 없대도!","JPN":"だから、子供には興味ないですってば！","ENG":"I told you, I'm not interested in kids!","TWN":"我說過，我對學生沒興趣！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"뭣보다 지금 그런 팔자 좋은 얘길 할 상황이 아니잖아요!","JPN":"何より、今こうしてのんびり話してる場合じゃないでしょう？","ENG":"Besides, we don't have time to talk!","TWN":"而且現在不是說這些的時候吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"확실히 그렇네요.","JPN":"確かにそうですね。","ENG":"You're right.","TWN":"的確是這樣沒錯。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"평화로운 학교에 무장병력을 들이다니, 그냥 두고 볼 수만은 없죠.","JPN":"平和な学校に武装兵力を投入するなんて、見過ごすわけにはいきません。","ENG":"I can't let the armed forces set foot on my peaceful campus.","TWN":"竟然把武裝兵力帶進和平的校園中，光是這樣，我就不能坐視不管。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"잠깐...... 서, 설마 관리국에서 날 잡으러 추적대를 보낸 건 아니겠지......?!","JPN":"待って……ま、まさか管理局が私を捕まえるために追跡隊を派遣したわけじゃないですよね……？","ENG":"Wait, they can't have come from the Administration to catch me, can they?","TWN":"等等……該、該不會是管理局為了抓我，派遣了追擊隊吧……？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"영문은 모르겠지만, 이디스를 도와주신 이상 여러분은 아카데미의 손님입니다.","JPN":"事情はわかりませんが、イーディスを助けてくださった以上、皆さんはアカデミーの客人です。","ENG":"I don't know the whole story, but you saved Edith. You're the Academy's guests now.","TWN":"雖然不知道原因，但既然你們幫助了伊蒂絲，那妳們就是我們學院的客人了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"총학생회의 이름을 걸고 여러분의 안전은 제가 책임지겠어요.","JPN":"総生徒会の名にかけて、私が責任を持って皆さんを守ります。","ENG":"As the president of the Student Council, I'll protect you.","TWN":"我會以學生會之名負起責任，保護各位的安全。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"다들 제 뒤로 물러서시길.","JPN":"皆さん、私の後ろに下がってください。","ENG":"Please get behind me.","TWN":"請都退到我身後吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};